import { useId, useInteractions, useListNavigation } from '@floating-ui/react';
import {
  ChangeEvent,
  Dispatch,
  forwardRef,
  HTMLAttributes,
  KeyboardEvent,
  ReactNode,
  SetStateAction,
  useCallback,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { usePopoverContext } from './Popover';
import { FilterValue } from '../FilterTypeConfig';
import { nullsSortLast } from '../utils';
import { Dimmer } from './Dimmer';
import { useVirtualizer } from '@tanstack/react-virtual';
import { QIcon } from './Icon';
import clsx from 'clsx';
import { QButton } from './Button';
import { QButtonGroup } from './ButtonGroup';
import { useAutoControlled } from '../hooks/useAutoControlled';

interface Option<T extends FilterValue> {
  value: T;
  text?: FilterValue;
  className?: string;
}

export interface QSearchableMultiSelectProps<T extends FilterValue> {
  search?: string;
  setSearch?: (search: string) => void;
  options: Option<T>[];
  selected: Set<T>;
  setSelected?: Dispatch<SetStateAction<Set<T>>>;
  onToggleValue?: (value: T) => void;
  placeholder?: string;
  clearSearchOnSelectOrClearAll?: boolean;
  loading?: boolean;
}
export function QSearchableMultiSelect<
  T extends string | null | undefined | number,
>({
  clearSearchOnSelectOrClearAll = false,
  loading,
  ...props
}: QSearchableMultiSelectProps<T>) {
  const { context, isPositioned, open } = usePopoverContext();
  const listDomRef = useRef<HTMLDivElement>(null);
  const listRef = useRef<(HTMLElement | null)[]>([]);
  const [activeIndex, setActiveIndex] = useState<number | null>(null);
  const [pointer, setPointer] = useState(false);
  const [showSelected, setShowSelected] = useState(false);

  const [search, setSearchLocal] = useAutoControlled({
    value: props.search,
    defaultValue: '',
    initialValue: '',
  });
  const setSearch = useCallback(
    (value: string) => {
      const setSearch = props.setSearch;
      setSearch?.(value);
      setSearchLocal(value);
    },
    [props.setSearch, setSearchLocal]
  );

  if (!open && pointer) {
    setPointer(false);
  }

  // Handles the list navigation where the reference is the inner input, not
  // the button that opens the floating element.
  const {
    getReferenceProps: getInputProps,
    getFloatingProps: getListFloatingProps,
    getItemProps,
  } = useInteractions([
    useListNavigation(context, {
      listRef,
      onNavigate: open ? setActiveIndex : undefined,
      activeIndex,
      cols: 1,
      orientation: 'vertical',
      loop: true,
      disabledIndices: [],
      // focusItemOnOpen: false,
      virtual: true,
      allowEscape: true,
      enabled: !loading,
    }),
  ]);

  const filteredOptions = useMemo(() => {
    const lowerSearch = search.trim().toLowerCase();
    if (!lowerSearch) return props.options;
    return props.options.filter((option) => {
      const lowerText = option.text?.toString().trim().toLowerCase();
      return lowerText?.includes(lowerSearch);
    });
  }, [props.options, search]);

  const optionsByValue = useMemo(
    () =>
      props.options.reduce(
        (map, value) => map.set(value.value, value),
        new Map<T, Option<T>>()
      ),
    [props.options]
  );

  const filteredSelected = useMemo(() => {
    const lowerSearch = search.trim().toLowerCase();
    const opts: Option<T>[] = [];
    props.selected.forEach((opt) => {
      if (
        !lowerSearch ||
        String(opt).toLowerCase().trim().includes(lowerSearch)
      ) {
        opts.push(optionsByValue.get(opt) ?? { value: opt, text: opt });
      }
    });
    return opts;
  }, [search, props.selected, optionsByValue]);

  const currentOptions = showSelected ? filteredSelected : filteredOptions;

  const filteredOpts = useMemo(
    () => currentOptions.sort((a, b) => nullsSortLast(a.text, b.text)),
    [currentOptions]
  );

  useLayoutEffect(() => {
    listRef.current.length = filteredOpts.length;
  }, [filteredOpts.length]);

  const rowVirtualizer = useVirtualizer({
    count: filteredOpts.length,
    getScrollElement: () => listDomRef.current,
    estimateSize: useCallback(() => 37.38, []),
    overscan: 10,
    getItemKey: useCallback(
      (index: number) =>
        filteredOpts[index]?.value ?? `[${filteredOpts[index]?.value}]`,
      [filteredOpts]
    ),
  });

  useLayoutEffect(() => {
    if (isPositioned && !pointer) {
      // Nothing has been selected, reset scrolling upon open
      // if (activeIndex === null && selectedIndex === null) {
      //   rowVirtualizer.scrollToIndex(0, {
      //     behavior: 'auto',
      //   });
      // }

      // Scrolling is restored, but the item will be scrolled
      // into view when necessary
      if (activeIndex !== null) {
        // listDomRef.current?.focus({ preventScroll: true });
        rowVirtualizer.scrollToIndex(activeIndex, {
          behavior: 'auto',
        });
      }
    }
  }, [rowVirtualizer, isPositioned, activeIndex, pointer]);

  const handleKeyDown = (event: KeyboardEvent) => {
    setPointer(false);
    if (event.key === 'Enter' && activeIndex !== null) {
      event.preventDefault();
      const opt = filteredOpts[activeIndex];
      props.onToggleValue?.(opt.value);
      props.setSelected?.((selected) => {
        const set = new Set(selected);
        if (set.has(opt.value)) {
          set.delete(opt.value);
        } else {
          set.add(opt.value);
        }
        return set;
      });
    }
  };

  const handleSearchChange = (ev: ChangeEvent<HTMLInputElement>) => {
    setActiveIndex(null);
    setSearch(ev.target.value);
  };

  const clear = () => {
    if (props.onToggleValue) {
      props.selected.forEach((opt) => {
        props.onToggleValue?.(opt);
      });
    }
    props.setSelected?.(new Set());
    if (clearSearchOnSelectOrClearAll) {
      setSearch('');
    }
  };

  const selectAll = () => {
    if (props.onToggleValue) {
      for (const opt of filteredOpts) {
        if (!props.selected.has(opt.value)) {
          props.onToggleValue(opt.value);
        }
      }
    }
    if (props.setSelected) {
      const set = new Set(filteredOpts.map((opt) => opt.value));
      props.setSelected(set);
    }
    if (clearSearchOnSelectOrClearAll) {
      setSearch('');
    }
  };

  return (
    <div className="qh-searchable-multi-select qh-multi-filter">
      <div>
        <QButtonGroup>
          <QButton
            className="qh-tab"
            active={!showSelected}
            variant="ghost"
            onClick={() => setShowSelected(false)}
          >
            All
          </QButton>
          <QButton
            className="qh-tab"
            active={showSelected}
            variant="ghost"
            onClick={() => setShowSelected(true)}
          >
            Selected{props.selected.size ? ` (${props.selected.size})` : ''}
          </QButton>
        </QButtonGroup>
      </div>
      <div className="qh-input">
        <input
          type="text"
          value={search}
          onChange={handleSearchChange}
          placeholder={props.placeholder}
          {...getInputProps({
            onChange: (e) =>
              setSearch((e.currentTarget as HTMLInputElement).value),
            onKeyDown: handleKeyDown,
          })}
          autoFocus
        />
        <QButton
          className="qh-clear"
          onClick={() => {
            setSearch('');
          }}
          title="Clear Search"
        >
          <QIcon name="close" />
        </QButton>
      </div>
      <div className="qh-dropdown-menu" ref={listDomRef} tabIndex={-1}>
        <div
          style={{
            height: `${rowVirtualizer.getTotalSize() || 50}px`,
            width: '100%',
            position: 'relative',
          }}
          {...getListFloatingProps({
            onKeyDown() {
              setPointer(false);
            },
            onPointerMove() {
              setPointer(true);
            },
          })}
        >
          <Dimmer active={loading} loader style={{ flexDirection: 'row' }} />
          {rowVirtualizer.getVirtualItems().map((virtualRow) => {
            const opt = filteredOpts[virtualRow.index];
            const display = opt.text ?? `[${opt.text}]`;
            return (
              <Option
                key={virtualRow.key}
                active={virtualRow.index === activeIndex}
                selected={props.selected.has(opt.value)}
                aria-setsize={filteredOpts.length}
                aria-posinset={virtualRow.index + 1}
                data-index={virtualRow.index}
                className={opt.className}
                {...getItemProps({
                  style: { transform: `translateY(${virtualRow.start}px)` },
                  ref: (el) => {
                    listRef.current[virtualRow.index] = el;
                    rowVirtualizer.measureElement(el);
                  },
                  onClick: () => {
                    props.onToggleValue?.(opt.value);

                    props.setSelected?.((selected) => {
                      const set = new Set(selected);
                      if (set.has(opt.value)) {
                        set.delete(opt.value);
                      } else {
                        set.add(opt.value);
                      }
                      return set;
                    });
                  },
                })}
              >
                {display}
              </Option>
            );
          })}
        </div>
      </div>
      <QButtonGroup fluid>
        <QButton onClick={selectAll}>Select All</QButton>
        <QButton onClick={clear}>Clear</QButton>
      </QButtonGroup>
    </div>
  );
}

type OptionProps = HTMLAttributes<HTMLDivElement> & {
  active: boolean;
  selected: boolean;
  children: ReactNode;
};

const Option = forwardRef<HTMLDivElement, OptionProps>(function Option(
  { active, selected, children, ...props },
  ref
) {
  const id = useId();
  return (
    <div
      {...props}
      ref={ref}
      id={id}
      role="option"
      aria-selected={selected}
      className={clsx(
        'qh-dropdown-item',
        { active, selected },
        props.className
      )}
    >
      <QIcon
        className="qh-check"
        name={selected ? 'check_box' : 'check_box_outline_blank'}
      />{' '}
      {children}
    </div>
  );
});
