import {
  ChangeEventHandler,
  FormEventHandler,
  ReactNode,
  useMemo,
  useState,
} from 'react';
import { QButton } from './components/Button';
import { Modal } from './components/Modal';
import { IconColorConfig, IconConfig, QuickView } from './types';
import { toCSSVariable } from './utils';
import { QIcon } from './components/Icon';
import { QSelect } from './components/QSelect';

export interface QuickViewModalProps {
  open: boolean;
  quickViews: QuickView[];
  values?: QuickView;
  header?: ReactNode | string;
  onEditQuickView?: (
    oldName: string | undefined,
    name: string,
    group?: string,
    icon?: string,
    color?: string,
    update?: boolean
  ) => void;
  onClose: () => void;
  icons: readonly IconConfig[];
  colors: readonly IconColorConfig[];
}

export const QuickViewModal = ({ ...props }: QuickViewModalProps) => {
  const [view, setView] = useState<Omit<QuickView, 'view'>>(
    props.values ?? { name: '', group: '', icon: '', color: '' }
  );
  const [update, setUpdate] = useState(false);

  const iconMap = useMemo(() => {
    return props.icons.reduce((acc, icon) => {
      acc.set(icon.label, icon.iconName);
      return acc;
    }, new Map<string, ReactNode>());
  }, [props.icons]);

  const usedNames = useMemo(
    () =>
      props.quickViews
        .reduce((opts, qv) => {
          opts.add(qv.name.toLowerCase());
          return opts;
        }, new Set<string>())
        // prevent prototype pollution
        .add('__proto__'),
    [props.quickViews]
  );
  const nameError = useMemo(() => {
    const lowerName = view.name.toLowerCase();
    return (
      usedNames.has(lowerName) && props.values?.name.toLowerCase() !== lowerName
    );
  }, [usedNames, view.name, props.values?.name]);
  const groups = useMemo(() => {
    const groups = new Set<string>();
    props.quickViews.forEach((qv) => {
      if (qv.group) {
        groups.add(qv.group);
      }
    });
    return groups;
  }, [props.quickViews]);
  const groupOptions = useMemo(
    () =>
      Array.from(groups).map((key) => ({
        key,
        text: key,
        value: key,
      })),
    [groups]
  );
  const handleChange: ChangeEventHandler<
    HTMLInputElement | HTMLSelectElement
  > = (evt) => {
    const allowed = ['name', 'group', 'color', 'icon'];
    const path = evt.currentTarget.name;
    if (!allowed.includes(path)) {
      return;
    }
    const value = evt.currentTarget.value;
    setView((prev) => ({ ...prev, [path]: value }));
  };

  const iconOptions = useMemo(() => {
    const iconOptions = props.icons
      .map<{
        value: string | null;
        text: string;
        render?: ReactNode;
      }>(({ iconName, label }) => ({
        key: label,
        value: label,
        text:
          label ??
          (typeof iconName === 'string'
            ? iconName
                .split('_')
                .map((word) => word[0].toUpperCase() + word.slice(1))
                .join(' ')
            : ''),
        render: (
          <>
            <span className="qh-icon">{iconName}</span>
            {label}
          </>
        ),
      }))
      .sort((a, b) => a.text.localeCompare(b.text));
    return iconOptions;
  }, [props.icons]);

  const iconColors = useMemo(() => {
    return props.colors
      .map(({ label, value }) => ({
        key: label,
        value,
        text: label,
      }))
      .sort((a, b) => a.text.localeCompare(b.text));
  }, [props.colors]);

  const handleSubmit: FormEventHandler<HTMLFormElement> = (evt) => {
    if (nameError) {
      evt.preventDefault();
      return;
    }
    const updateView = props.values ? !!update : true;
    props.onEditQuickView?.(
      props.values?.name,
      view.name,
      view.group || undefined,
      view.icon || undefined,
      view.color || undefined,
      updateView
    );
  };
  return (
    <>
      <Modal
        open={props.open}
        onClose={props.onClose}
        header={
          props.header ||
          (props.values
            ? `Edit Quick View: ${props.values.name}`
            : 'Create Quick View')
        }
        onSubmit={handleSubmit}
        footer={(ref) => (
          <>
            {props.values && (
              <label style={{ display: 'flex', alignItems: 'center' }}>
                Update View Settings to the Current Settings&nbsp;
                <input
                  checked={update}
                  onChange={(ev) => setUpdate(ev.currentTarget.checked)}
                  type="checkbox"
                  id="update"
                  name="update"
                />
              </label>
            )}
            <QButton
              type="button"
              onClick={() => ref.current?.close()}
              variant="ghost"
            >
              Cancel
            </QButton>
            <QButton value="default" formMethod="dialog">
              Confirm
            </QButton>
          </>
        )}
        mainClassName="qh-qv-modal-main"
      >
        <div className="qh-form-field">
          <label htmlFor="name">
            Name
            <QIcon
              name="asterisk"
              color="var(--qh-icon-color-red)"
              size="0.8em"
            />
          </label>
          <input
            id="name"
            name="name"
            autoComplete="off"
            placeholder="Name..."
            value={view.name}
            onChange={handleChange}
            required
            maxLength={30}
            // tell 1password not to try and autofill here...
            data-1p-ignore
          />
          <div
            className="qh-form-field-detail error"
            style={{ minHeight: '1lh' }}
          >
            {nameError && (
              <>
                <QIcon color="var(--qh-icon-color-red)" name="warning" />
                This name already exists
              </>
            )}
          </div>
        </div>
        <div className="qh-form-field">
          <label htmlFor="group">Group</label>
          <input
            list="group-list"
            id="group"
            name="group"
            value={view.group}
            onChange={handleChange}
            placeholder="No Group"
            // tell 1password not to try and autofill here...
            data-1p-ignore
          />
          <datalist id="group-list">
            {groupOptions.map((option) => (
              <option key={option.key} value={option.value}>
                {option.text}
              </option>
            ))}
          </datalist>
        </div>
        <div className="qh-form-field">
          <label htmlFor="color">Color</label>
          <select
            id="color"
            name="color"
            value={view.color}
            onChange={handleChange}
          >
            <option value="">Default</option>
            {iconColors.map((option) => (
              <option key={option.key} value={option.value}>
                {option.text}
              </option>
            ))}
          </select>
        </div>
        <div className="qh-form-field">
          <label htmlFor="icon">Icon</label>
          <QSelect
            id="icon"
            className="qh-mso-select"
            popoverClassName="qh-mso-select"
            options={iconOptions.map((option) => ({
              text: option.text,
              value: option.value,
              render: option.render,
            }))}
            value={view.icon || null}
            onChange={(icon) => setView((prev) => ({ ...prev, icon }))}
            placeholder="No Icon"
            clearable
          ></QSelect>
        </div>
        <div style={{ minHeight: '1lh', gridColumn: 'span 2' }}>
          {view.icon && (
            <>
              <span
                className="qh-icon"
                style={{
                  color: view.color ? toCSSVariable(view.color) : undefined,
                }}
              >
                {iconMap.get(view.icon)}
              </span>
              {` ${view.name}`}
            </>
          )}
        </div>
      </Modal>
    </>
  );
};
