import clsx from 'clsx';
import { QIcon } from '../components/Icon';
import { CSSProperties, MouseEventHandler, forwardRef } from 'react';
import { QButton } from '../components/Button';

export interface FilterTriggerProps {
  active?: boolean;
  className?: string;
  style?: CSSProperties;
  onClick?: MouseEventHandler<HTMLElement>;
}
export const FilterTrigger = forwardRef<HTMLButtonElement, FilterTriggerProps>(
  function FilterTrigger({ active, className, ...props }, ref) {
    return (
      <QButton
        size="mini"
        variant="ghost"
        compact
        {...props}
        className={clsx('qh-filter-indicator', className)}
        ref={ref}
        aria-label="Filter Column"
        data-filtered={active || undefined}
      >
        {active ? filteredIcon : unfilteredIcon}
      </QButton>
    );
  }
);
const filteredIcon = (
  <i className="qh-icons active">
    <QIcon name="filter_alt" />
    <QIcon name="asterisk" corner />
  </i>
);
const unfilteredIcon = <QIcon name="filter_alt" />;
