import type { FetchAsyncFunc } from './types';

export const sortCollator = new Intl.Collator(undefined, {
  numeric: true,
  caseFirst: 'upper',
  ignorePunctuation: true,
  sensitivity: 'case',
  usage: 'sort',
});

export function nullsSortLast(
  a: string | number | null | undefined,
  b: string | number | null | undefined
) {
  if (a == null && b == null) return 0;
  if (a == null) return 1;
  if (b == null) return -1;
  // the collator will cast them to strings on its own.
  return sortCollator.compare(a as string, b as string);
}

type DebouncedFunc<T extends Function> = T & { clear: () => void };
export function debounce<T extends Function>(
  func: T,
  time?: number
): DebouncedFunc<T> {
  let timeoutId: ReturnType<typeof setTimeout> | undefined;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const debounced = ((...args: any[]) => {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      func(...args);
    }, time);
  }) as unknown as DebouncedFunc<T>;
  debounced.clear = () => {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
  };
  return debounced;
}

export function toCSSVariable(value: string) {
  if (value.startsWith('--')) {
    return `var(${value})`;
  }
  return value;
}

export function isCancel(error: unknown) {
  return (
    error instanceof Error &&
    // check for either fetch cancel or axios cancel!
    (error.name === 'AbortError' || error.name === 'CanceledError')
  );
}

export const fetchBasic: FetchAsyncFunc = async (_type, request) => {
  const res = await fetch(request);
  return await (res.ok ? res.json() : Promise.reject(res));
};

const _ignoreValue = Symbol('ignoreValue');
type IgnoreValue = typeof _ignoreValue;
/**
 * A sentinel value to indicate that a result should be excluded from the final result.
 *
 * This works on {@link groupToMap}, {@link keyByMap}, {@link setBy}, {@link filterMap}, and {@link iteratorFilterMap} to indicate that the value should be ignored
 */
export const zIgnore: IgnoreValue = _ignoreValue as IgnoreValue;

type FunctionOrProperty<T> = keyof T | ((value: T) => unknown);

type ReturnOrPropertyType<V, T> = V extends (value: T) => unknown
  ? Exclude<ReturnType<V>, IgnoreValue>
  : V extends keyof T
    ? T[V]
    : never;

/**
 * Turn an iterable into a Map, grouping by the iteratee, with the value based on valueIteratee
 * the Map's values will be an array of all values that have the same key
 * If the key or value is {@link zIgnore}, it will be filtered out
 * @param list any iterable
 * @param iteratee A property or function to use to get the key for the Map
 * @param valueIteratee A property of function to use to get the value that will be stored in the Map
 * @returns A Map with the keys and value arrays based on the iteratee and valueIteratee
 * @example
 * ```ts
 * import { groupToMap, zIgnore } from 'zDash';
 * const array = [
 *  { id: 1, value: 'hi' },
 * { id: 2, value: 'meow' },
 * { id: 3, value: 'hi' },
 * { id: 4, value: 'grr' },
 * ];
 * const map = groupToMap(array, 'id'); //=> Map<number, { id: number, value: string }[]>
 * //=> Map(4) { 1 => [ { id: 1, value: 'hi' } ], 2 => [ { id: 2, value: 'meow' } ], 3 => [ { id: 3, value: 'hi' } ], 4 => [ { id: 4, value: 'grr' } ] }
 * const map2 = groupToMap(array, 'value', 'id'); //=> Map<string, number[]>
 * //=> Map(3) { 'hi' => [ 1, 3 ], 'meow' => [ 2 ], 'grr' => [ 4 ] }
 * const map3 = groupToMap(array, (v) => v.value, (v) => `${v.id}:${v.value}`); //=> Map<string, string[]>
 * //=> Map(3) { 'hi' => [ '1:hi', '3:hi' ], 'meow' => [ '2:meow' ], 'grr' => [ '4:grr' ] }
 * const map = groupToMap(array, ({id})=> id > 2 ? id : zIgnore, 'value'); //=> Map<number, string[]>
 * //=> Map(2) { 3 => [ 'hi' ], 4 => [ 'grr' ] }
 * ```
 */
export function groupToMap<
  T,
  K extends FunctionOrProperty<T>,
  V extends FunctionOrProperty<T> = (value: T) => T,
>(
  list: Iterable<T> | undefined | null,
  iteratee: K,
  valueIteratee?: V
): Map<ReturnOrPropertyType<K, T>, ReturnOrPropertyType<V, T>[]> {
  type MK = ReturnOrPropertyType<K, T>;
  type MV = ReturnOrPropertyType<V, T>;
  const map = new Map<MK, MV[]>();
  if (list == null) return map;
  const iterateeIsFunction = typeof iteratee === 'function';
  const valueIterateeIsFunction = typeof valueIteratee === 'function';
  for (const value of list) {
    const key = (
      iterateeIsFunction ? iteratee(value) : value[iteratee as keyof T]
    ) as MK;
    if (key === zIgnore) continue;
    const mapValue = (
      valueIteratee == null
        ? value
        : valueIterateeIsFunction
          ? valueIteratee(value)
          : value[valueIteratee as keyof T]
    ) as MV;
    if (mapValue === zIgnore) continue;
    if (!map.has(key)) {
      map.set(key, [mapValue]);
    } else {
      map.get(key)!.push(mapValue);
    }
  }
  return map;
}

/**
 * Turn an iterable into a Map, grouping by the iteratee, with the value based on valueIteratee
 * The Map's values will be the last value that had the same key
 * If the key or value is {@link zIgnore}, it will be filtered out
 * @param list any iterable
 * @param iteratee A property or function to use to get the key for the Map
 * @param valueIteratee A property of function to use to get the value that will be stored in the Map
 * @returns A Map with the keys and values based on the iteratee and valueIteratee
 * @example
 * ```ts
 *  import { keyByMap, zIgnore } from 'zDash';
 *  const array = [
 *    { id: 1, value: 'hi' },
 *    { id: 2, value: 'meow' },
 *    { id: 3, value: 'hi' },
 *    { id: 4, value: 'grr' },
 *  ];
 * const map = keyByMap(array, 'id'); //=> Map<number, { id: number, value: string }>
 * //=> Map(4) { 1 => { id: 1, value: 'hi' }, 2 => { id: 2, value: 'meow' }, 3 => { id: 3, value: 'hi' }, 4 => { id: 4, value: 'grr' } }
 * const map2 = keyByMap(array, 'value', 'id'); //=> Map<string, number>
 * //=> Map(3) { 'hi' => 3, 'meow' => 2, 'grr' => 4 }
 * const map3 = keyByMap(array, (v) => v.value, (v) => `${v.id}:${v.value}`); //=> Map<string, string>
 * //=> Map(3) { 'hi' => '3:hi', 'meow' => '2:meow', 'grr' => '4:grr' }
 * const map = keyByMap(array, ({id})=> id > 2 ? id : zIgnore, 'value'); //=> Map<number, string>
 * //=> Map(2) { 3 => 'hi', 4 => 'grr' }
 * ```
 */
export function keyByMap<
  T,
  K extends FunctionOrProperty<T>,
  V extends FunctionOrProperty<T> = (value: T) => T,
>(
  list: Iterable<T> | undefined | null,
  iteratee: K,
  valueIteratee?: V
): Map<ReturnOrPropertyType<K, T>, ReturnOrPropertyType<V, T>> {
  type MV = ReturnOrPropertyType<V, T>;
  type MK = ReturnOrPropertyType<K, T>;
  const map = new Map<MK, MV>();
  if (list == null) return map;
  const iterateeIsFunction = typeof iteratee === 'function';
  for (const value of list) {
    const key = (
      iterateeIsFunction ? iteratee(value) : value[iteratee as keyof T]
    ) as MK;
    if (key === zIgnore) continue;
    const mapValue = (
      valueIteratee == null
        ? value
        : typeof valueIteratee === 'function'
          ? valueIteratee(value)
          : value[valueIteratee as keyof T]
    ) as MV;
    if (mapValue !== zIgnore) {
      map.set(key, mapValue);
    }
  }
  return map;
}
