import { useCallback, useEffect, useMemo, useReducer, useRef } from 'react';
import { fetchBasic, isCancel } from '../utils';
import { useLiveRef } from './useLiveRef';

// /**
//  * @callback processData
//  * @param data
//  * @return processed Data
//  */
// /**
//  * @callback onError
//  * @param error
//  */

// /**
//  * @property  processData - If present, will process the data before setting it to the state. Must return the processed data.
//  * @property  onError
//  * @property  withCredentials
//  * @property  deps - If present, the axios call will be re-performed/cleanedup whenever deps changes
//  * @property  runIf - If Present, the axios call will not be performed if this returns false.
//  * @property  cacheKey - If Present, will store the result from the last axios call to the same URL with the same cacheKey
//  */

export interface AxiosHookConfig<T, Y> {
  /**If present, will process the data before setting it to the state. Must return the processed data.*/
  processData?: (data: T) => Y;
  onError?: (error: Error) => void;
  withCredentials?: boolean;
  /**If present, the axios call will be re-performed/cleanedup whenever deps changes*/
  deps?: ReadonlyArray<unknown>;
  /**If present, the axios call will only be performed if this returns true.*/
  runIf?: () => boolean;
  /**If present, will store the result from the last axios call to the same URL with the same cacheKey*/
  cacheKey?: string;
  fetchAsync?: (type: string, request: Request) => Promise<T>;
  fetchAsyncType: string;
  preRequest?: (request: Request) => Request;
}

const cache: { [key: string]: unknown } = {};
const keyDelim = '\u200C';

interface RequestConfig {
  url: string;
  method?: string;
  params?: object;
  data?: object;
  headers?: HeadersInit;
  withCredentials?: RequestCredentials;
}

export function useAxios<T, Y = T>(
  config: RequestConfig,
  hookConfig: AxiosHookConfig<T, Y>
): AxiosState<Y> & { trigger: () => void } {
  const {
    processData,
    onError,
    withCredentials,
    deps = [],
    runIf,
    cacheKey,
  } = hookConfig;
  const [state, dispatch] = useReducer(axiosReducer<T>, {
    loading: true,
    error: {},
  });
  const processedData = useMemo<Y>(() => {
    if (!state.data) return state.data as unknown as Y;
    return processData ? processData(state.data) : (state.data as unknown as Y);
  }, [state.data, processData]);
  // const [first, setFirst] = useState(true);

  const abortController = useRef<AbortController>(undefined);
  const fetchAsyncRef = useLiveRef(hookConfig.fetchAsync ?? fetchBasic);
  const fetchAsyncTypeRef = useLiveRef(hookConfig.fetchAsyncType);
  const fetchData = useCallback(() => {
    abortController.current?.abort();
    const key = `${config.url}${keyDelim}${cacheKey}${keyDelim}${deps.join(
      keyDelim
    )}`;
    if (cacheKey && cache[key]) {
      const data = cache[key];
      dispatch({ type: 'data', payload: data as T });
      return;
    }
    abortController.current = new AbortController();
    dispatch({ type: 'loading' });
    const url = new URL(config.url, window.location.href);
    if (config.params) {
      Object.entries(config.params).forEach(([key, value]) => {
        if (value == undefined) return;
        url.searchParams.append(key, value as string);
      });
    }
    const headers: HeadersInit = {
      Accept: 'application/json',
      ...config.headers,
    };
    if (config.method?.toLowerCase() !== 'get') {
      headers['Content-Type'] = 'application/json';
    }
    const requestBase = new Request(config.url, {
      credentials: (withCredentials && 'include') || config.withCredentials,
      body: config.data ? JSON.stringify(config.data) : undefined,
      headers,
      signal: abortController.current.signal,
      method: config.method,
    });
    const request = hookConfig.preRequest?.(requestBase) ?? requestBase;
    fetchAsyncRef
      .current(fetchAsyncTypeRef.current as 'vocab', request)
      .then((data) => {
        if (cacheKey) {
          cache[key] = data;
        }
        dispatch({ type: 'data', payload: data as T });
      })
      .catch((err) => {
        if (isCancel(err)) return;
        dispatch({ type: 'error', payload: err });
        onError?.(err);
      });
    return () => abortController.current?.abort();
    // eslint-disable-next-line
  }, [...deps]);
  useEffect(() => {
    if (runIf && !runIf()) {
      dispatch({ type: 'noRun' });
      return;
    }
    return fetchData();
    // eslint-disable-next-line
  }, [fetchData]);

  const fetchRef = useRef(fetchData);
  fetchRef.current = fetchData;
  const trigger = useCallback(() => {
    fetchRef.current();
  }, []);
  return {
    loading: state.loading,
    data: processedData,
    error: state.error,
    trigger,
  };
}

/**
 * @param url - Url to query
 * @param  params - Parameters
 * @param  hookConfig
 */
export function useAxiosGet<T, Y = T>(
  url: string,
  hookConfig: AxiosHookConfig<T, Y>,
  params?: object
): AxiosState<Y> & { trigger: () => void } {
  return useAxios({ url, params, method: 'GET' }, hookConfig);
}

type AxiosState<T> = { error?: object; data?: T; loading: boolean };

type Actions<T> =
  | { type: 'loading' }
  | { type: 'error'; payload: object }
  | { type: 'data'; payload: T }
  | { type: 'noRun' };

function axiosReducer<T>(
  state: AxiosState<T>,
  action: Actions<T>
): AxiosState<T> {
  switch (action.type) {
    case 'loading':
      return { ...state, error: undefined, loading: true };
    case 'error':
      return { ...state, error: action.payload, loading: false };
    case 'data':
      return {
        ...state,
        error: undefined,
        loading: false,
        data: action.payload,
      };
    case 'noRun':
      return { ...state, error: undefined, loading: false };
    default:
      return state;
  }
}
