import {
  DragEventHandler,
  useEffect,
  useLayoutEffect,
  useMemo,
  useRef,
  useState,
} from 'react';
import { QHGridProps } from '../QHGrid';
import { QButton, QButton as QHButton } from '../components/Button';
import {
  BaseGrouping,
  FilterValues,
  InnerColumnConfig,
  ObjectLiteral,
} from '../types';
import { debounce } from '../utils';
import { QIcon } from '../components/Icon';
import {
  QPopover,
  QPopoverContent,
  QPopoverTrigger,
} from '../components/Popover';
import { QSearchableMultiSelect } from '../components/QSearchableMultiSelect';

export interface CaptionProps<Data extends ObjectLiteral, ATI> {
  columns: InnerColumnConfig<Data, ATI>[];
  onColumnVisibilityToggle?: QHGridProps<Data, ATI>['onColumnVisibilityToggle'];
  grouping: BaseGrouping[]; //<Data, ATI>[];
  onGroupChange?: QHGridProps<Data, ATI>['onGroupChange'];
  generalSearch: string;
  generalSearchDebounceTime?: number;
  onGeneralSearch?: QHGridProps<Data, ATI>['onGeneralSearch'];
  extraHeaderItem?: QHGridProps<Data, ATI>['extraHeaderItem'];
  loading?: boolean;
  onExportExcel?: () => void;
  filters: FilterValues;
}
export function Caption<Data extends ObjectLiteral, ATI>(
  props: CaptionProps<Data, ATI>
) {
  const onGeneralSearch = useMemo(
    () =>
      props.onGeneralSearch
        ? debounce(props.onGeneralSearch, props.generalSearchDebounceTime)
        : undefined,
    [props.onGeneralSearch, props.generalSearchDebounceTime]
  );
  const inputRef = useRef<HTMLInputElement>(null);
  useEffect(() => {
    // Imperatively control the input value
    // This is needed because the input is debounced
    // This allows keeping the input updated when a quick view is selected
    if (inputRef.current) {
      inputRef.current.value = props.generalSearch;
    }
  }, [props.generalSearch]);
  function onClearSearch() {
    // // That way it doesn't look like the button lagged to the user while it is debouncing!
    if (inputRef.current) {
      // Need to clear it here in case the user typed something in and then cleared it before the debounce finished.
      inputRef.current.value = '';
    }
    // reset the debouncing, so that there isn't a reversion
    onGeneralSearch?.clear();
    // Call the actual handler without any debouncing
    props.onGeneralSearch?.('');
  }

  // For Grouping
  const onDrop = (evt) => {
    const colId = evt.dataTransfer.getData('colId');
    if (!colId) {
      return;
    }
    if (grouping.find((group) => group.colId === colId)) {
      return;
    }
    props.onGroupChange?.(
      grouping
        .map((group) => ({
          colId: group.colId,
          sortOrder: group.sortOrder,
        }))
        .concat({ colId: colId, sortOrder: 'asc' })
    );
  };

  const allowDrop: DragEventHandler<HTMLTableCellElement> = (evt) => {
    if (evt.dataTransfer.types[0] === 'colid') {
      evt.preventDefault();
    }
  };

  const { columns, grouping } = props;
  const selected = useMemo(
    () =>
      columns.reduce(
        (set, col) => (col.hidden ? set : set.add(col.id)),
        new Set<string>()
      ),
    [columns]
  );
  const columnOptions = useMemo(
    () =>
      columns.map((column) => ({
        value: column.id,
        text: column.title,
        className: props.filters[column.id] ? 'filtered' : undefined,
      })),
    [columns, props.filters]
  );

  const handleRemoveGroupBy = (colId: string) => {
    props.onGroupChange?.(grouping.filter((group) => group.colId !== colId));
  };
  const handleGroupSortToggle = (colId: string) => {
    const sortSwitch: { [key in 'asc' | 'desc']: 'asc' | 'desc' } = {
      asc: 'desc',
      desc: 'asc',
    };
    props.onGroupChange?.(
      grouping.map<BaseGrouping>((group) =>
        group.colId === colId
          ? {
              colId: group.colId,
              sortOrder: sortSwitch[group.sortOrder],
            }
          : group
      )
    );
  };
  const groupMenuItems = grouping.map((group) => {
    const colId = group.colId;
    const col = columns.find((col) => col.id === group.colId);
    const sortIcon =
      group.sortOrder === 'asc' ? (
        <QIcon name="arrow_upward_alt" />
      ) : (
        <QIcon name="arrow_downward_alt" />
      );
    return (
      <div className="qh-button-group" key={colId}>
        <QHButton
          variant="outlined"
          size="mini"
          onClick={() => handleGroupSortToggle(colId)}
        >
          {sortIcon}
          {col?.title || colId}
        </QHButton>
        <QHButton
          size="mini"
          onClick={() => handleRemoveGroupBy(colId)}
          variant="outlined"
          compact
        >
          X
        </QHButton>
      </div>
    );
  });
  const controlsShown = !!(
    onGeneralSearch ||
    props.onColumnVisibilityToggle ||
    props.extraHeaderItem ||
    props.onExportExcel
  );

  const groupingShown = !!props.onGroupChange;
  const [captionRef, setCaptionRef] = useState<HTMLDivElement | null>(null);
  const [resizeObserver] = useState(
    () =>
      new ResizeObserver((entries) => {
        entries.forEach((entry) => {
          const target = entry.target as HTMLDivElement;
          const [{ blockSize } = { blockSize: 0 }] = entry.borderBoxSize;
          const root = target.closest('.qh-root') as HTMLDivElement;
          if (root) {
            root.style.setProperty('--qh-caption-height', `${blockSize}px`);
          }
        });
      })
  );
  useLayoutEffect(() => {
    if (!captionRef) return;
    resizeObserver.observe(captionRef, { box: 'border-box' });
    return () => {
      resizeObserver.unobserve(captionRef);
    };
  }, [captionRef, resizeObserver]);
  if (!controlsShown && !groupingShown) {
    return null;
  }
  return (
    <div className="qh-caption" ref={setCaptionRef}>
      {controlsShown && (
        <div className="QHGrid--header qh-caption--controls">
          {onGeneralSearch && (
            <div className="qh-input QHGrid--generalSearch qh-general-search">
              <input
                type="text"
                ref={inputRef}
                placeholder="Search..."
                onChange={(ev) => onGeneralSearch(ev.currentTarget.value)}
              />
              <QButton
                className="qh-clear"
                title="Clear Search"
                onClick={onClearSearch}
              >
                <QIcon name="close" />
              </QButton>
            </div>
          )}
          {props.onColumnVisibilityToggle && (
            <QPopover>
              <QPopoverTrigger variant="outlined">
                <QIcon name="table_view" /> Columns
              </QPopoverTrigger>
              <QPopoverContent className="qh-column-toggle">
                <QSearchableMultiSelect
                  options={columnOptions}
                  selected={selected}
                  onToggleValue={props.onColumnVisibilityToggle}
                  clearSearchOnSelectOrClearAll
                />
              </QPopoverContent>
            </QPopover>
          )}
          {props.extraHeaderItem}
          {!props.loading && !!props.onExportExcel && (
            <>
              <span className="qh-spacer" />
              <QHButton
                className="qh-export-button"
                onClick={() => props.onExportExcel!()}
                variant="ghost"
                title="Export to Excel"
              >
                <QIcon name="file_save" />
              </QHButton>
            </>
          )}
        </div>
      )}
      {props.onGroupChange && (
        <div
          className="qh-caption--grouping"
          onDrop={onDrop}
          onDragOver={allowDrop}
        >
          {groupMenuItems}
          {!groupMenuItems.length &&
            'Drag a column header and drop it here to group by that column'}
        </div>
      )}
    </div>
  );
}
