import clsx from 'clsx';
import dayjs from 'dayjs';
import { orderBy } from 'lodash-es';
import {
  ReactNode,
  Ref,
  RefObject,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
} from 'react';
import { filterTypes } from './FilterTypeConfig';
import { QHGridBody } from './Grid/Body';
import { Caption } from './Grid/Caption';
import { Headers } from './Grid/Headers';
import { QHGridColumnConfig } from './Grid/types';
import { useLiveRef } from './hooks/useLiveRef';
import {
  getExportTemplate,
  getFieldSortValueFunction,
  getFieldValue,
} from './selectors/QHGridSelector';
import {
  BaseGrouping,
  FilterValues,
  Grouping,
  InnerColumnConfig,
  ObjectLiteral,
  RowClickHandler,
  RowLevelPropsCalc,
  RowLevelStyleCalc,
  SharedQHGridProps,
} from './types';
import { Dimmer } from './components/Dimmer';
import { QMessage } from './components/QMessage';
import { Footer } from './Grid/Footer';

const stubFunction = () => ({});
const stubArray = [];

type fetchData = () => void;

export interface QHGridRef<Data extends ObjectLiteral, ATI> {
  /**
   * A reference to the scroll-body div that wraps the table
   */
  bodyRef: Ref<HTMLDivElement>;
  /**
   * The full data set, after sorting and filtering
   *
   * In a network grid, this will be the same as slicedData
   */
  data: Data[];
  /**
   * The current page's data
   */
  slicedData: Data[];
  /**
   * Exports the current data to an excel file with the given name
   * @param name The name of the file
   * @returns
   */
  exportExcel: (name?: string) => Promise<void>;
  /**
   * The props that were passed in to the grid
   */
  props: QHGridProps<Data, ATI>;
  /**
   * Returns sortedData
   * @deprecated
   */
  getSortedData: () => Data[];
}
export interface QHGridProps<Data extends ObjectLiteral, ATI>
  extends SharedQHGridProps<Data, ATI> {
  /**
   * class name to apply to the root element
   */
  className?: string;
  columns: InnerColumnConfig<Data, ATI>[];
  data: Data[];
  filters: FilterValues;
  /**
   * Called after the data is filtered with the new filteredData
   */
  onFiltered?: (data: Data[]) => void;
  sortBy: string | null;
  sortOrder: 'asc' | 'desc' | null;
  onSort?: (colId: string) => void;
  /**
   * Called after the filtered data is sorted with the new sortedData
   */
  onSorted?: (data: Data[]) => void;
  grouping: BaseGrouping[];
  onGroupChange?: (grouping: BaseGrouping[]) => void;
  generalSearch: string;
  generalSearchDebounceTime?: number;
  onGeneralSearch?: (value: string) => void;
  isPaginated?: boolean;
  totalRows?: number;
  loading?: boolean;
  loadingMessage?: ReactNode;
  additionalTemplateInfo: ATI;
  rowLevelStyleCalc?: RowLevelStyleCalc<Data>;
  /**
   * A function that allows you to take the item and index and return props that should be applied to the row
   */
  rowLevelPropsCalc?: RowLevelPropsCalc<Data>;
  onRowClick?: RowClickHandler<Data>;
  onReloadData?: fetchData;
  getExportData?: () => Promise<Data[]> | Data[];
  emptyMessage?: string | ReactNode;
  extraHeaderItem?: ReactNode;
  columnsConfig: InnerColumnConfig<Data, ATI>[];
  itemsPerPage: number;
  onItemsPerPageChange?: (itemsPerPage: number) => void;
  height?: string;
  activePage: number;
  onPageChange: (activePage: number) => void;
  onColumnVisibilityToggle?: (colId: string) => void;
  onColumnReorder?: (curIdx: number, newIdx: number) => void;
  onFilterUpdate?: (field: string, type) => (value) => void;
  qhGridRef?: RefObject<QHGridRef<Data, ATI> | null>;
}

export function QHGrid<Data extends ObjectLiteral, ATI>(
  allProps: QHGridProps<Data, ATI>
) {
  const {
    loadingMessage = 'Loading Data... Please Wait...',
    emptyMessage = 'No Data Available',
    height = '70vh',
    generalSearchDebounceTime = 500,
    grouping = stubArray,
    activePage,
    itemsPerPage,
    ...props
  } = allProps;
  const bodyRef = useRef<HTMLDivElement>(null);

  const filteredData = useMemo<Data[]>(() => {
    let data = props.data;
    if (props.isPaginated) {
      return data;
    }
    if (Object.keys(props.filters).length) {
      const filters = Object.entries(props.filters);
      data = data.filter((item) => {
        let include = true;
        for (const [field, { type, value }] of filters) {
          const { filter } = filterTypes[type] ?? {};
          if (!filter) {
            continue;
          }
          include = filter(item, field, value);
          if (!include) break;
        }
        return include;
      });
    }
    if (props.generalSearch) {
      const generalLowerCase = props.generalSearch.toLowerCase();
      data = data.filter((item) => {
        return props.columnsConfig
          .map((col) => {
            return getFieldValue(item, col.field, col.type);
          })
          .join('\u200C')
          .toLowerCase()
          .includes(generalLowerCase);
      });
    }
    return data;
  }, [
    props.data,
    props.generalSearch,
    props.filters,
    props.isPaginated,
    props.columnsConfig,
  ]);
  const onFilteredRef = useLiveRef(props.onFiltered);
  useEffect(() => {
    // Let parent know that new filtered data is available if they are interested
    onFilteredRef.current?.(filteredData);
  }, [filteredData, onFilteredRef]);
  const handlePageChange = (activePage: number) => {
    if (typeof activePage !== 'number') {
      return;
    }
    props.onPageChange?.(activePage);

    if (bodyRef.current) {
      bodyRef.current.scrollTop = 0;
    }
  };

  const handleItemsPerPageChange = (value: number) => {
    const newItemsPerPage = value;
    if (typeof newItemsPerPage !== 'number') {
      return;
    }
    if (itemsPerPage !== newItemsPerPage) {
      props.onItemsPerPageChange?.(newItemsPerPage);
    }
  };

  // const { data = stubArray } = props;

  const visibleColumns = useMemo<QHGridColumnConfig<Data, ATI>[]>(() => {
    return props.columns
      .map((col, idx) => ({ ...col, QHgridIndex: idx }))
      .filter((col) => !col.hidden);
  }, [props.columns]);

  const itemKeyMap = useMemo(() => {
    const uniqueColumns = props.columns.filter((col) => col.unique);
    return (item: Data) =>
      uniqueColumns.length
        ? uniqueColumns
            .map((col) => getFieldValue(item, col.field, col.type))
            .join(',')
        : undefined;
  }, [props.columns]);

  const { columnsConfig = props.columns } = props;

  const numRows = props.totalRows ?? filteredData.length;

  const numPages = Math.ceil(numRows / itemsPerPage) || 1;

  const realStartIndex = (activePage - 1) * itemsPerPage || 0;
  const realEndIndex =
    activePage * itemsPerPage > numRows ? numRows : activePage * itemsPerPage;
  let startIndex = realStartIndex;
  let endIndex = realEndIndex;
  if (props.isPaginated) {
    startIndex = 0;
    endIndex = itemsPerPage;
  }
  const columnsById = useMemo(
    () => new Map(columnsConfig.map((col) => [col.id, col])),
    [columnsConfig]
  );
  const groupingWithExtraStuff = useMemo<Grouping<Data, ATI>[]>(() => {
    return grouping.reduce<Grouping<Data, ATI>[]>((grouping, group) => {
      const col = columnsById.get(group.colId);
      if (col) {
        grouping.push({
          ...group,
          field: col.field,
          title: col.title,
          type: col.type,
        });
      }
      return grouping;
    }, []);
  }, [grouping, columnsById]);

  const sortedData = useMemo(() => {
    if ((!grouping.length && !props.sortBy) || props.isPaginated) {
      return filteredData;
    }
    const groups = grouping.reduce<
      (BaseGrouping & { col: InnerColumnConfig<Data, ATI> })[]
    >((groups, group) => {
      const column = columnsById.get(group.colId);
      if (column) {
        groups.push({
          ...group,
          col: column,
        });
      }
      return groups;
    }, []);
    if (props.sortBy && props.sortOrder) {
      const col = columnsById.get(props.sortBy);
      if (col) {
        groups.push({ col, sortOrder: props.sortOrder, colId: props.sortBy });
      }
    }
    const sortBys = groups.map((group) =>
      getFieldSortValueFunction(group.col.field, group.col.type)
    );

    const sortOrders = groups.map((group) => group.sortOrder);

    return orderBy(filteredData, sortBys, sortOrders);
  }, [
    props.sortBy,
    props.sortOrder,
    grouping,
    filteredData,
    columnsById,
    props.isPaginated,
  ]);
  const onSortedRef = useLiveRef(props.onSorted);
  useEffect(() => {
    // Let parent know that new sorted data is available if they are interested
    onSortedRef.current?.(sortedData);
  }, [sortedData, onSortedRef]);
  const slicedData = useMemo(() => {
    return sortedData.slice(startIndex, endIndex);
  }, [sortedData, startIndex, endIndex]);

  const {
    onGroupChange,
    onColumnVisibilityToggle,
    loading,
    generalSearch,
    onGeneralSearch,
    extraHeaderItem,
    additionalTemplateInfo,
    getExportData,
    onExcelExport,
  } = props;

  const onExcelExportRef = useLiveRef(onExcelExport);

  const exportExcel = useCallback(async () => {
    const cols = props.columns;
    const onExcelExport = onExcelExportRef.current;
    if (!onExcelExport) return;
    const dataPromise: Promise<Data[]> | Data[] =
      getExportData?.() ?? sortedData;

    const data = await dataPromise;
    const visibleColumns = cols.filter((col) => {
      const notHidden = !col.hidden;
      const hideOnExport = col.hideOnExport;

      let visibleDueToOtherCol = false;
      if (col.exportIfVisible) {
        const dependentCol = cols.find((depCol) => {
          return depCol.id === col.exportIfVisible;
        });

        visibleDueToOtherCol = !dependentCol?.hidden;
      }
      return (notHidden && !hideOnExport) || visibleDueToOtherCol;
    });
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const toWsCols = (aoaData: any[][]) => {
      return aoaData[0].map((_col, idx) => {
        return {
          width: Math.max(
            ...aoaData.map((row) => {
              const value = row[idx];
              const colWidth =
                value instanceof Date ? 18 : `${value}`.length * 1.5;
              return colWidth > 70 ? 70 : colWidth < 18 ? 18 : colWidth;
            })
          ),
        };
      });
    };
    const toArrayOfArrays = () => {
      const exportMainData = data.map((item) => {
        return visibleColumns.map((col) => {
          const template = getExportTemplate(col);
          let value = getFieldValue(item, col.field, col.type);
          if (template) value = template(value, item, additionalTemplateInfo);

          if (Array.isArray(value)) {
            value = value.join(' : ');
          }
          return dayjs.isDayjs(value) ? dayjs(value).toDate() : value;
        });
      });
      const exportData = [
        visibleColumns.map((col) => {
          return col.exportTitle || col.title;
        }),
      ].concat(exportMainData);
      return exportData;
    };
    onExcelExport({
      toWsCols,
      data,
      visibleColumns,
      toArrayOfArrays,
    });
  }, [
    props.columns,
    onExcelExportRef,
    getExportData,
    sortedData,
    additionalTemplateInfo,
  ]);
  useImperativeHandle(
    props.qhGridRef,
    () => {
      return {
        bodyRef,
        exportExcel,
        data: sortedData,
        slicedData,
        props: allProps,
        getSortedData: () => sortedData,
        sortedData,
      };
    },
    [exportExcel, sortedData, slicedData, allProps]
  );
  return (
    <div
      className={clsx('QHGrid qh-grid qh-root', props.className)}
      style={{ width: '100%', margin: 0, padding: 0 }}
    >
      <Dimmer active={props.loading} loader className="QHGrid--loading">
        {loadingMessage}
      </Dimmer>
      <Caption
        columns={props.columns}
        grouping={grouping}
        onGroupChange={onGroupChange}
        onColumnVisibilityToggle={onColumnVisibilityToggle}
        loading={loading}
        generalSearch={generalSearch}
        onGeneralSearch={onGeneralSearch}
        onExportExcel={onExcelExport ? exportExcel : undefined}
        generalSearchDebounceTime={generalSearchDebounceTime}
        extraHeaderItem={extraHeaderItem}
        filters={props.filters}
      />
      <div
        className="QHGrid-body-div qh-scroll-body"
        style={{ height: height }}
        ref={bodyRef}
      >
        <table className="QHGrid--body qh-table">
          <colgroup>
            {grouping.length > 0 && <col span={grouping.length} />}
            {visibleColumns.map((column) => (
              <col style={column.columnStyle} key={column.id || column.title} />
            ))}
          </colgroup>
          <thead>
            <tr>
              {grouping.map((_group, groupIdx) => {
                return (
                  <th
                    className="qh-grouping-spacer"
                    key={groupIdx}
                    style={{ cursor: 'default' }}
                  />
                );
              })}
              <Headers
                filters={props.filters}
                onFilterUpdate={props.onFilterUpdate}
                rawData={props.data}
                onColumnReorder={props.onColumnReorder}
                sortBy={props.sortBy}
                sortOrder={props.sortOrder}
                onSort={props.onSort}
                columns={props.columns}
                enableDrag={!!props.onGroupChange}
                fetchAsync={props.fetchAsync}
              />
            </tr>
          </thead>
          <tbody>
            <QHGridBody
              startIndex={realStartIndex}
              rowLevelStyleCalc={props.rowLevelStyleCalc || stubFunction}
              rowLevelPropsCalc={props.rowLevelPropsCalc}
              additionalTemplateInfo={props.additionalTemplateInfo}
              onRowClick={props.onRowClick || stubFunction}
              itemKeyMap={itemKeyMap}
              grouping={groupingWithExtraStuff}
              visibleColumns={visibleColumns}
              slicedData={slicedData}
            />
          </tbody>
        </table>
        {!props.loading && numRows === 0 && (
          <div className="QHGrid--empty qh-grid--empty">
            {!!emptyMessage && typeof emptyMessage === 'string' ? (
              <QMessage icon="search" content={emptyMessage} />
            ) : (
              emptyMessage
            )}
          </div>
        )}
      </div>
      <Footer
        activePage={activePage}
        itemsPerPage={itemsPerPage}
        numRows={numRows}
        realStartIndex={realStartIndex}
        realEndIndex={realEndIndex}
        onPageChange={handlePageChange}
        onItemsPerPageChange={handleItemsPerPageChange}
        onReloadData={props.onReloadData}
        totalPages={numPages}
      />
    </div>
  );
}
