import { ReactNode } from 'react';
import { QIcon } from './Icon';

export interface QMessageProps {
  /**
   * If a string, it will be used as the ligature icon name using the icons that are part of the QHGrid package.
   */
  icon?: ReactNode;
  header?: ReactNode;
  content?: ReactNode;
}
/**
 * A message component that can be used to display information to the user.
 * It can be used to display a message with an icon, a header and a body.
 * @param props
 * @returns
 */
export function QMessage(props: QMessageProps) {
  return (
    <div className="qh-message">
      {props.icon && (
        <div className="qh-message--icon">
          {typeof props.icon === 'string' ? (
            <QIcon name={props.icon} />
          ) : (
            props.icon
          )}
        </div>
      )}
      <div className="qh-message--content">
        {props.header && (
          <div className="qh-message--header">{props.header}</div>
        )}
        {props.content && (
          <div className="qh-message--body">{props.content}</div>
        )}
      </div>
    </div>
  );
}
