const stubArray = [];

// type filterAccessor = string | number | object | ((item: Data) => any);

export interface MFProps<Data extends ObjectLiteral> extends MFBaseProps {
  selectedOpts?: FilterValue[];
  data: Data[];
  field: Paths<Data>;
  onChange: (opts?: FilterValue[]) => void;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  accessor: any;
  columnName?: string;
  columnId?: string;
}

interface InternalMFBaseProps {
  selected: Set<FilterValue>;
  options: Set<FilterValue>;
  onChange: (opts?: FilterValue[]) => void;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  accessor: any;
  clearSearchOnSelectOrClearAll?: boolean;
  onOpen?: () => void;
  loading?: boolean;
  columnName?: string;
  columnId?: string;
}

function MultiFilterBase({
  options,
  selected,
  onChange,
  accessor,
  clearSearchOnSelectOrClearAll = false,
  onOpen,
  loading,
  columnName,
  columnId,
}: InternalMFBaseProps) {
  const [open, setOpen] = useState(false);
  const triggerOpen = (open: boolean) => {
    if (open) {
      onOpen?.();
    }
    setOpen(open);
  };
  const [search, setSearch] = useState('');
  const optionsMapped = useMemo(
    () =>
      Array.from(options, (value) => ({
        value,
        text: getAccessorValue(value, accessor),
      })),
    [options, accessor]
  );
  return (
    <QPopover open={open} onOpenChange={triggerOpen}>
      <QPopoverTrigger
        asChild
        onClick={(ev) => {
          triggerOpen(!open);
          ev.stopPropagation();
        }}
      >
        <FilterTrigger active={selected.size > 0} />
      </QPopoverTrigger>
      <QPopoverContent
        onClick={(ev) => ev.stopPropagation()}
        data-column={columnName}
        data-column-id={columnId}
      >
        <QSearchableMultiSelect
          clearSearchOnSelectOrClearAll={clearSearchOnSelectOrClearAll}
          loading={loading}
          options={optionsMapped}
          selected={selected}
          setSelected={(action) => {
            const set =
              typeof action === 'function' ? action(selected) : action;
            onChange(set.size ? Array.from(set) : undefined);
          }}
          search={search}
          setSearch={setSearch}
          placeholder="Search"
        />
      </QPopoverContent>
    </QPopover>
  );
}

// type MFOpt = string | null | undefined;

export function MultiFilterDropdown<Data extends ObjectLiteral>({
  selectedOpts = stubArray,
  data,
  field,
  onChange,
  accessor,
  ...props
}: MFProps<Data>) {
  const selectedOptsSet = useMemo(() => {
    return new Set(selectedOpts);
  }, [selectedOpts]);
  const optionsSet = useMemo(() => {
    return new Set<FilterValue>(
      data.flatMap((item) => getFieldValue(item, field))
    );
  }, [data, field]);

  return (
    <MultiFilterBase
      accessor={accessor}
      onChange={onChange}
      options={optionsSet}
      selected={selectedOptsSet}
      clearSearchOnSelectOrClearAll={props.clearSearchOnSelectOrClearAll}
      columnId={props.columnId}
      columnName={props.columnName}
    />
  );
}

export interface RMFProps<Data extends ObjectLiteral> extends RMFBaseProps {
  selectedOpts?: FilterValue[];
  data: Data[];
  field: Paths<Data>;
  onChange: (opts?: FilterValue[]) => void;
  fetchAsync?: FetchAsyncFunc;
  columnName?: string;
  columnId?: string;
}
export function RemoteMultiFilterDropdown<Data extends ObjectLiteral>({
  selectedOpts = stubArray,
  data,
  field,
  onChange,
  accessor,
  useLocal,
  remotePreRequest,
  processData: configProcessData,
  ...props
}: RMFProps<Data>) {
  const selectedOptsSet = useMemo(() => {
    return new Set(selectedOpts);
  }, [selectedOpts]);
  const remoteParamsString = useMemo(
    () => new URLSearchParams(props.remoteParams).toString(),
    [props.remoteParams]
  );
  const processData = useCallback(
    (data: FilterValue[]) => {
      if (configProcessData) {
        const processedData = configProcessData(data);
        if (!(processedData instanceof Set)) {
          throw new TypeError(
            `processData must return a Set for ${props.remoteUrl}?${remoteParamsString}`
          );
        }
        return processedData;
      }
      return new Set(data);
    },
    [configProcessData, props.remoteUrl, remoteParamsString]
  );
  const {
    data: remoteOptions,
    loading,
    trigger: loadOptions,
  } = useAxiosGet<FilterValue[], Set<FilterValue>>(
    props.remoteUrl,
    {
      runIf: () => !!props.prefetch,
      processData,
      fetchAsyncType: 'vocab',
      fetchAsync: props.fetchAsync as AxiosHookConfig<
        FilterValue[],
        Set<FilterValue>
      >['fetchAsync'],
      preRequest: remotePreRequest,
      deps: [props.remoteUrl, remoteParamsString, processData],
    },
    props.remoteParams
  );
  const onOpen = useCallback(() => {
    if (remoteOptions || loading) {
      return;
    }
    loadOptions();
  }, [loading, loadOptions, remoteOptions]);

  const localOptions: Set<FilterValue> = useMemo(() => {
    if (!useLocal) {
      return new Set();
    }
    return new Set(data.flatMap((item) => getFieldValue(item, field)));
  }, [data, useLocal, field]);
  const optionsSet = useMemo(() => {
    if (!localOptions.size) {
      return remoteOptions ?? new Set<FilterValue>();
    }
    const set = new Set(localOptions);
    remoteOptions?.forEach((value) => set.add(value));
    return set;
  }, [remoteOptions, localOptions]);

  return (
    <MultiFilterBase
      accessor={accessor}
      onChange={onChange}
      options={optionsSet}
      selected={selectedOptsSet}
      clearSearchOnSelectOrClearAll={props.clearSearchOnSelectOrClearAll}
      loading={loading}
      onOpen={onOpen}
      columnName={props.columnName}
      columnId={props.columnId}
    />
  );
}

export interface DateFilterOpts {
  startDate: string;
  endDate: string;
}
export interface DateFilterProps {
  onChange: (opts?: DateFilterOpts) => void;
  selectedOpts?: DateFilterOpts;
  columnName?: string;
  columnId?: string;
}
const initialDateFilterOpts = { startDate: '', endDate: '' };

export function DateFilterDropdown(props: DateFilterProps) {
  const { selectedOpts = initialDateFilterOpts } = props;
  const setValue = useCallback(
    (name: string, value: string) => {
      const newOpts = {
        ...selectedOpts,
        [name]: value,
      };
      if (!Object.values(newOpts).some(Boolean)) {
        props.onChange?.();
      } else {
        props.onChange?.(newOpts);
      }
    },
    [props, selectedOpts]
  );
  const handleChange: ChangeEventHandler<HTMLInputElement> = (ev) => {
    setValue(ev.currentTarget.name, ev.currentTarget.value);
  };
  const { startDate, endDate } = selectedOpts;
  const id = useId();
  const startDateId = `${id}-startDate`;
  const endDateId = `${id}-endDate`;
  return (
    <QPopover>
      <QPopoverTrigger
        asChild
        onClick={(ev) => {
          ev.stopPropagation();
        }}
      >
        <FilterTrigger active={!!props.selectedOpts} />
      </QPopoverTrigger>
      <QPopoverContent
        onClick={(ev) => ev.stopPropagation()}
        className="qh-date-filter"
        data-column={props.columnName}
        data-column-id={props.columnId}
      >
        <div className="qh-input">
          <label htmlFor={startDateId}>From:&nbsp;</label>
          <input
            type="date"
            style={{ cursor: 'pointer' }}
            value={startDate}
            name="startDate"
            id={startDateId}
            onChange={handleChange}
          />
          <QButton
            variant="ghost"
            aria-label="Clear"
            onClick={() => setValue('startDate', '')}
          >
            <QIcon name="close" />
          </QButton>
        </div>
        <div className="qh-input">
          <label htmlFor={endDateId}>Until:&nbsp;</label>
          <span style={{ flexGrow: 1 }} />
          <input
            type="date"
            style={{ cursor: 'pointer' }}
            value={endDate}
            name="endDate"
            id={endDateId}
            onChange={handleChange}
          />
          <QButton
            variant="ghost"
            aria-label="Clear"
            onClick={() => setValue('endDate', '')}
          >
            <QIcon name="close" />
          </QButton>
        </div>
      </QPopoverContent>
    </QPopover>
  );
}

const singleComparisons = {
  [Comparisons.null]: true,
  [Comparisons.notNull]: true,
  [Comparisons.empty]: true,
  [Comparisons.notEmpty]: true,
};

export interface AlphanumericOpt {
  comparison: Comparisons;
  combination: Combinations;
  value: string;
}
export interface AlphanumericFilterProps {
  onChange: (opts?: AlphanumericOpt[]) => void;
  selectedOpts: AlphanumericOpt[];
  filterSubType: 'numeric' | 'alphanumeric';
  columnName?: string;
  columnId?: string;
}
const combinations: { text: string; value: Combinations }[] = [
  {
    text: 'And',
    value: Combinations.and,
  },
  { text: 'Or', value: Combinations.or },
];

const isComparisonActive = (opts) =>
  singleComparisons[opts.comparison] || opts.value;
function useComparisonFilter(
  selectedOptsProp: AlphanumericOpt[] | undefined,
  onChange: (opts?: AlphanumericOpt[]) => void,
  initialState: AlphanumericOpt
) {
  const [selectedOpts, setSelectedOpts] = useState(
    selectedOptsProp ?? [initialState]
  );
  const handleAdd = useCallback(
    (_evt) => {
      setSelectedOpts((selectedOpts) => [...selectedOpts, initialState]);
    },
    [initialState]
  );
  const handleChange = useCallback<
    ChangeEventHandler<HTMLSelectElement | HTMLInputElement>
  >((evt) => {
    evt.stopPropagation();
    const { name, value } = evt.currentTarget;
    const idx = Number(evt.currentTarget.dataset['idx']);
    if (
      !name ||
      Number.isNaN(idx) ||
      !['comparison', 'combination', 'value'].includes(name)
    ) {
      return;
    }
    setSelectedOpts((selectedOpts) => {
      const options = selectedOpts.slice();
      options[idx] = { ...options[idx], [name]: value };
      return options;
    });
  }, []);
  const handleClear = useCallback(() => {
    setSelectedOpts([initialState]);
    onChange();
  }, [onChange, initialState]);
  const handleFilter = useCallback(() => {
    if (!selectedOpts.some(isComparisonActive)) {
      onChange();
    } else {
      onChange(selectedOpts);
    }
  }, [onChange, selectedOpts]);
  const handleOpen = useCallback(() => {
    // If there are active filters, overwrite the current state.
    // Otherwise, keep what the user had changed for convenience
    if (selectedOptsProp?.some(isComparisonActive)) {
      setSelectedOpts(selectedOptsProp);
    }
  }, [selectedOptsProp]);
  const handleRemove = useCallback<MouseEventHandler<HTMLButtonElement>>(
    (evt) => {
      const idx = Number(evt.currentTarget.dataset['idx']);
      if (!Number.isNaN(idx)) {
        setSelectedOpts((selectedOpts) => {
          if (selectedOpts.length === 1) {
            return [initialState];
          }
          const array = selectedOpts.slice();
          array.splice(idx, 1);
          return array;
        });
      }
    },
    [initialState]
  );
  return {
    handleAdd,
    handleChange,
    handleClear,
    handleFilter,
    handleOpen,
    handleRemove,
    selectedOpts,
  };
}

const numericInitialState: AlphanumericOpt = {
  combination: Combinations.and,
  comparison: Comparisons.equals,
  value: '',
};

const alphanumericInitialState: {
  comparison: Comparisons;
  combination: Combinations;
  value: string;
} = {
  combination: Combinations.and,
  comparison: Comparisons.contains,
  value: '',
};

export function AlphanumericFilterPopup({
  onChange,
  filterSubType,
  ...props
}: AlphanumericFilterProps) {
  const initialState =
    filterSubType === 'numeric'
      ? numericInitialState
      : alphanumericInitialState;
  const comparisons =
    filterSubType === 'numeric' ? numericComparisons : alphanumericComparisons;
  const filter = useComparisonFilter(
    props.selectedOpts,
    onChange,
    initialState
  );
  const filterInputs = filter.selectedOpts.map((opts, idx) => {
    const combination =
      idx > 0 ? (
        <div
          className={clsx('combination', {
            'qh-divider': opts.combination === Combinations.and,
          })}
        >
          <select
            value={opts.combination}
            name="combination"
            data-idx={idx}
            onChange={filter.handleChange}
          >
            {combinations.map((option) => (
              <option key={option.value} value={option.value}>
                {option.text}
              </option>
            ))}
          </select>
        </div>
      ) : null;
    return (
      <Fragment key={idx}>
        {combination}
        <div className="values">
          <div>
            <select
              value={opts.comparison}
              name="comparison"
              data-idx={idx}
              onChange={filter.handleChange}
            >
              {comparisons.map((option) => (
                <option key={option.value} value={option.value}>
                  {option.text}
                </option>
              ))}
            </select>
            {!singleComparisons[opts.comparison] && (
              <input
                data-idx={idx}
                name="value"
                type={filterSubType === 'numeric' ? 'number' : 'text'}
                step={filterSubType === 'numeric' ? 'any' : undefined}
                value={opts.value}
                onChange={filter.handleChange}
              />
            )}
          </div>
          <QButton
            compact
            onClick={filter.handleRemove}
            data-idx={idx}
            variant="ghost"
          >
            <QIcon name="delete" />
          </QButton>
        </div>
      </Fragment>
    );
  });
  const [open, setOpen] = useState(false);
  return (
    <QPopover
      open={open}
      onOpenChange={(open) => {
        setOpen(open);
        if (open) filter.handleOpen();
      }}
      modal
    >
      <QPopoverTrigger
        asChild
        onClick={(ev) => {
          setOpen(!open);
          if (!open) {
            filter.handleOpen();
          }
          ev.stopPropagation();
        }}
      >
        <FilterTrigger active={!!props.selectedOpts?.length} />
      </QPopoverTrigger>
      <QPopoverContent
        onClick={(ev) => ev.stopPropagation()}
        className="qh-comparison-filter"
        data-column={props.columnName}
        data-column-id={props.columnId}
      >
        <main>
          {filterInputs}
          <div className="qh-divider">
            <QButton
              className="add"
              compact
              onClick={filter.handleAdd}
              variant="ghost"
            >
              <QIcon name="add_circle" size="1.5rem" />
            </QButton>
          </div>
          <QButtonGroup fluid style={{ position: 'sticky', bottom: '0px' }}>
            <QButton onClick={filter.handleFilter}>Filter</QButton>
            <QButton onClick={filter.handleClear}>Clear</QButton>
          </QButtonGroup>
        </main>
      </QPopoverContent>
    </QPopover>
  );
}
