import { FormEvent, ReactNode, RefObject, useRef } from 'react';
import { Dialog, DialogProps } from './Dialog';
import clsx from 'clsx';

type RenderProp = (ref: RefObject<HTMLDialogElement | null>) => ReactNode;
export interface ModalProps extends Omit<DialogProps, 'children' | 'modal'> {
  header?: ReactNode | RenderProp;
  footer?: ReactNode | RenderProp;
  children?: ReactNode | RenderProp;
  onSubmit?: (event: FormEvent<HTMLFormElement>) => void;
  formClassName?: string;
  mainClassName?: string;
}

export const Modal = ({
  className,
  children,
  footer,
  header,
  onSubmit,
  formClassName,
  mainClassName,
  ...props
}: ModalProps) => {
  const ref = useRef<HTMLDialogElement>(null);
  return (
    <Dialog ref={ref} modal className={clsx('qh-modal', className)} {...props}>
      <form onSubmit={onSubmit} className={formClassName}>
        {header && (
          <header>{typeof header === 'function' ? header(ref) : header}</header>
        )}
        <main className={mainClassName}>
          {typeof children === 'function' ? children(ref) : children}
        </main>
        {footer && (
          <footer>{typeof footer === 'function' ? footer(ref) : footer}</footer>
        )}
      </form>
    </Dialog>
  );
};
